using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private static readonly List<Instructor> Instructors =
    [
        new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Email = "schen@university.edu", Bio = "Dr. Chen has over 15 years of experience in software engineering and distributed systems. She has published extensively in top-tier conferences and holds several patents in cloud computing." },
        new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor of Mathematics", Email = "jmiller@university.edu", Bio = "Dr. Miller specializes in applied mathematics and statistics. His research focuses on machine learning theory and its applications in biomedical sciences." },
        new() { Id = 3, Name = "Prof. Maria Garcia", Title = "Professor of Biology", Email = "mgarcia@university.edu", Bio = "Prof. Garcia is a leading researcher in molecular biology and genetics. She directs the university's Genomics Lab and has mentored over 30 graduate students." },
        new() { Id = 4, Name = "Dr. Robert Kim", Title = "Assistant Professor of History", Email = "rkim@university.edu", Bio = "Dr. Kim is a historian of modern East Asia with a focus on transnational cultural exchange. He is the author of two books and contributes regularly to academic journals." },
        new() { Id = 5, Name = "Dr. Emily Watson", Title = "Professor of Chemistry", Email = "ewatson@university.edu", Bio = "Dr. Watson's research in organic chemistry has led to breakthroughs in pharmaceutical synthesis. She is the recipient of multiple national research awards." },
        new() { Id = 6, Name = "Prof. David Okafor", Title = "Professor of English Literature", Email = "dokafor@university.edu", Bio = "Prof. Okafor is an acclaimed scholar of postcolonial literature. His critical essays and anthologies are widely used in university curricula worldwide." },
    ];

    private static readonly List<Department> Departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Biology", Code = "BIO", Description = "Study of living organisms and life processes." },
        new() { Id = 4, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        new() { Id = 5, Name = "Chemistry", Code = "CHEM", Description = "Study of matter, its properties, and reactions." },
        new() { Id = 6, Name = "English", Code = "ENG", Description = "Study of English language, literature, and writing." },
    ];

