@using CourseCatalog.Models

<div class="card h-100 shadow-sm featured-card">
    <div class="card-body">
        <span class="badge bg-primary mb-2">@Course.Code</span>
        <span class="badge bg-secondary mb-2">@Course.Credits Credits</span>
        <h5 class="card-title">@Course.Title</h5>
        <p class="card-text text-muted">@Course.DepartmentName</p>
        <p class="card-text">@Truncate(Course.Description, 120)</p>
    </div>
    <div class="card-footer bg-transparent border-top-0">
        <a href="@($"courses/{Course.Id}")" class="btn btn-outline-primary btn-sm">View Details</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Course Course { get; set; } = default!;

    private static string Truncate(string text, int maxLength)
        => text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@using CourseCatalog.Models

<a href="@($"courses/{Course.Id}")" class="text-decoration-none">
    <div class="card mb-3 course-card">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-start">
                <div>
                    <h5 class="card-title mb-1">
                        <span class="badge bg-primary me-2">@Course.Code</span>
                        @Course.Title
                    </h5>
                    <p class="text-muted mb-1">@Course.DepartmentName &middot; @Course.Credits credits &middot; @Course.Instructor.Name</p>
                    <p class="card-text mb-0">@Truncate(Course.Description, 160)</p>
                </div>
                <div class="text-end ms-3 flex-shrink-0">
                    <small class="text-muted">@Course.Schedule</small>
                </div>
            </div>
        </div>
    </div>
</a>

@code {
    [Parameter, EditorRequired]
    public Course Course { get; set; } = default!;

    private static string Truncate(string text, int maxLength)
        => text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@using CourseCatalog.Models

<div class="row g-3 mb-4">
    <div class="col-md-8">
        <input type="text"
               class="form-control"
               placeholder="Search courses by title, code, or keyword…"
               value="@SearchTerm"
               @oninput="OnSearchInput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" value="@DepartmentId" @onchange="OnDepartmentChange">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public int DepartmentId { get; set; }
    [Parameter] public List<Department> Departments { get; set; } = [];
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }
    [Parameter] public EventCallback<int> DepartmentIdChanged { get; set; }

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        await SearchTermChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }

    private async Task OnDepartmentChange(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var id))
        {
            await DepartmentIdChanged.InvokeAsync(id);
        }
    }
}

