@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<div class="container-fluid py-4">
    <h1 class="mb-4">📝 Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
            <hr />
            <p class="mb-0">You will receive a confirmation at your university email. <a href="courses">Browse more courses</a>.</p>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-lg-8">
                <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger mb-3" />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
                        <ValidationMessage For="() => model.StudentName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" placeholder="e.g. S12345" />
                        <ValidationMessage For="() => model.StudentId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="courseSelect" class="form-label">Course</label>
                        <InputSelect id="courseSelect" class="form-select" @bind-Value="model.CourseId">
                            <option value="0">— Select a course —</option>
                            @if (courses is not null)
                            {
                                @foreach (var course in courses)
                                {
                                    <option value="@course.Id">@course.Code — @course.Title</option>
                                }
                            }
                        </InputSelect>
                        <ValidationMessage For="() => model.CourseId" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-success btn-lg">Submit Enrollment Request</button>
                </EditForm>
            </div>
            <div class="col-lg-4">
                <div class="card bg-light">
                    <div class="card-body">
                        <h5>ℹ️ How It Works</h5>
                        <ol class="mb-0">
                            <li>Fill in your name and student ID</li>
                            <li>Select the course you wish to enroll in</li>
                            <li>Submit your request</li>
                            <li>You'll receive a confirmation email within 2 business days</li>
                        </ol>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private EnrollmentRequest model = new();
    private List<Course>? courses;
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        courses = await CatalogService.GetCoursesAsync();

        if (PreselectedCourseId.HasValue)
        {
            model.CourseId = PreselectedCourseId.Value;
        }
    }

    private async Task HandleSubmit()
    {
        var course = courses?.FirstOrDefault(c => c.Id == model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";

        await CatalogService.SubmitEnrollmentAsync(model);
        submitted = true;
    }
}

