@page "/courses/{Id:int}"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course") — University Course Catalog</PageTitle>

<div class="container-fluid py-4">
    @if (course is null)
    {
        <div class="alert alert-warning">
            <h4>Course not found</h4>
            <p>The requested course does not exist. <a href="courses">Browse all courses</a>.</p>
        </div>
    }
    else
    {
        <nav aria-label="breadcrumb" class="mb-3">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/">Home</a></li>
                <li class="breadcrumb-item"><a href="courses">Courses</a></li>
                <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
            </ol>
        </nav>

        <div class="mb-4">
            <h1>@course.Code — @course.Title</h1>
            <span class="badge bg-primary me-2">@course.DepartmentName</span>
            <span class="badge bg-secondary">@course.Credits Credits</span>
        </div>

        <div class="row">
            <div class="col-lg-8">
                <div class="card mb-4">
                    <div class="card-header">
                        <h5 class="mb-0">📖 Description</h5>
                    </div>
                    <div class="card-body">
                        <p>@course.Description</p>
                    </div>
                </div>

                <InstructorBio Instructor="course.Instructor" />
            </div>

            <div class="col-lg-4">
                <CourseSchedule Course="course" />

                <a href="@($"enroll?courseId={course.Id}")" class="btn btn-success btn-lg w-100">
                    📝 Request Enrollment
                </a>
            </div>
        </div>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override async Task OnInitializedAsync()
    {
        course = await CatalogService.GetCourseByIdAsync(Id);
    }
}

