@page "/"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container-fluid py-4">
    <div class="text-center mb-5">
        <h1 class="display-5 fw-bold">🎓 University Course Catalog</h1>
        <p class="lead text-muted">Explore our departments and find the right courses for your academic journey.</p>
        <a href="courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
        <a href="enroll" class="btn btn-outline-success btn-lg">Enroll Now</a>
    </div>

    <section class="mb-5">
        <h2 class="mb-3">⭐ Featured Courses</h2>
        @if (featuredCourses is null)
        {
            <p><em>Loading…</em></p>
        }
        else
        {
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
                @foreach (var course in featuredCourses)
                {
                    <div class="col">
                        <FeaturedCourseCard Course="course" />
                    </div>
                }
            </div>
        }
    </section>

    <section>
        <h2 class="mb-3">🏛️ Departments</h2>
        @if (departments is null)
        {
            <p><em>Loading…</em></p>
        }
        else
        {
            <DepartmentLinkList Departments="departments" />
        }
    </section>
</div>

@code {
    private List<Course>? featuredCourses;
    private List<Department>? departments;

    protected override async Task OnInitializedAsync()
    {
        featuredCourses = await CatalogService.GetFeaturedCoursesAsync();
        departments = await CatalogService.GetDepartmentsAsync();
    }
}

